<script>export let title,size,modal=false,open=false,closeButton=true,closeOnEscape=true;let el,shown=open;const id=title.toLowerCase().replace(/\W/g,'-');function show(){shown=true;setTimeout(()=>modal?el.showModal():el.show())}function close(){el.close();shown=false}function cancel(e){if(!closeOnEscape)e.preventDefault()}</script><section class="dialog-demo"><strong>{modal?'Modal':title}</strong>{#if !shown}<button onclick={show}>Open dialog</button>{/if}<dialog bind:this={el} open={shown&&!modal} class="kumo-dialog {size}" aria-labelledby={id} aria-describedby={id+'-desc'} aria-modal={modal||undefined} oncancel={cancel} onclose={()=>shown=false}><h2 id={id} class="dialog-title">{title}</h2><p id={id+'-desc'} class="dialog-description">Dialog content and keyboard behavior preview.</p>{#if closeButton}<button class="dialog-close" aria-label="Close" onclick={close}>×</button>{/if}<div class="dialog-actions"><button onclick={close}>Cancel</button><button class="primary" onclick={close}>Confirm</button></div></dialog></section>